INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Side_To_Side_Chins','Side To Side Chins','dorsales',ARRAY['bíceps','antebrazos','espalda media','hombros'],'otro','strength',ARRAY['Grab the pull-up bar with the palms facing forward using a wide grip.','As you have both arms extended in front of you holding the bar at a wide grip, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up while leaning to the left hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space (no swinging) and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of contraction, inhale as you go back to the starting position.','Now, pull your torso up while leaning to the right hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of contraction, inhale as you go back to the starting position.','Repeat steps 3-6 until you have performed the prescribed amount of repetitions for each side.'],'Grab the pull-up bar with the palms facing forward using a wide grip. As you have both arms extended in front of you holding the bar at a wide grip, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position. Pull your torso up while leaning to the left hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space (no swinging) and only the arms should move. The forearms should do no other work other than hold the bar. After a second of contraction, inhale as you go back to the starting position. Now, pull your torso up while leaning to the right hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar. After a second of contraction, inhale as you go back to the starting position. Repeat steps 3-6 until you have performed the prescribed amount of repetitions for each side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_To_Side_Chins/0.jpg','exercisedb',true),('Side_Wrist_Pull','Side Wrist Pull','hombros',ARRAY['antebrazos','dorsales'],NULL,'stretching',ARRAY['This stretch works best standing. Cross your left arm over the midline of your body and hold the left wrist in your right hand down at the level of your hips. Start the stretch with a bent left arm.','Slowly straighten, pull, and lift it up to shoulder height, as pictured. Feel this stretch originate in your back, not your shoulders, and don''''t pull too hard on the shoulders joint. Switch sides.'],'This stretch works best standing. Cross your left arm over the midline of your body and hold the left wrist in your right hand down at the level of your hips. Start the stretch with a bent left arm. Slowly straighten, pull, and lift it up to shoulder height, as pictured. Feel this stretch originate in your back, not your shoulders, and don''t pull too hard on the shoulders joint. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Wrist_Pull/0.jpg','exercisedb',true),('Side_to_Side_Box_Shuffle','Side to Side Box Shuffle','cuádriceps',ARRAY['abductores','aductores','pantorrillas','isquiotibiales'],'otro','plyometrics',ARRAY['Stand to one side of the box with your left foot resting on the middle of it.','To begin, jump up and over to the other side of the box, landing with your right foot on top of the box and your left foot on the floor. Swing your arms to aid your movement.','Continue shuffling back and forth across the box.'],'Stand to one side of the box with your left foot resting on the middle of it. To begin, jump up and over to the other side of the box, landing with your right foot on top of the box and your left foot on the floor. Swing your arms to aid your movement. Continue shuffling back and forth across the box.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_to_Side_Box_Shuffle/0.jpg','exercisedb',true),('Single-Arm_Cable_Crossover','Single-Arm Cable Crossover','pecho',ARRAY[]::text[],'cable','strength',ARRAY['Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand.','Step forward in front of both pulleys with your arms extended in front of you, bringing your hands together. Your head and chest should be up as you lean forward, while your feet should be staggered. This will be your starting position.','Keeping your left arm in place, allow your right arm to extend out to the side, maintaining a slight bend at the elbow. The right arm should be perpendicular to the body at approximately shoulder level.','Return your arm back to the starting position by pulling your hand back to the midline of the body.','Hold for a second at the starting position and repeat the movement on the opposite side. Continue alternating back and forth for the prescribed number of repetitions.'],'Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand. Step forward in front of both pulleys with your arms extended in front of you, bringing your hands together. Your head and chest should be up as you lean forward, while your feet should be staggered. This will be your starting position. Keeping your left arm in place, allow your right arm to extend out to the side, maintaining a slight bend at the elbow. The right arm should be perpendicular to the body at approximately shoulder level. Return your arm back to the starting position by pulling your hand back to the midline of the body. Hold for a second at the starting position and repeat the movement on the opposite side. Continue alternating back and forth for the prescribed number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Arm_Cable_Crossover/0.jpg','exercisedb',true),('Single-Arm_Linear_Jammer','Single-Arm Linear Jammer','hombros',ARRAY['pecho','tríceps'],'barra','strength',ARRAY['Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.','Raise the bar from the floor, taking it to your shoulders with one or both hands. Adopt a wide stance. This will be your starting position.','Perform the movement by extending the elbow, pressing the weight up. Move explosively, extending the hips and knees fully to produce maximal force.','Return to the starting position.'],'Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight. Raise the bar from the floor, taking it to your shoulders with one or both hands. Adopt a wide stance. This will be your starting position. Perform the movement by extending the elbow, pressing the weight up. Move explosively, extending the hips and knees fully to produce maximal force. Return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Arm_Linear_Jammer/0.jpg','exercisedb',true),('Single-Arm_Push-Up','Single-Arm Push-Up','pecho',ARRAY['hombros','tríceps'],'peso corporal','strength',ARRAY['Begin laying prone on the ground. Move yourself into a position supporting your weight on your toes and one arm. Your working arm should be placed directly under the shoulder, fully extended. Your legs should be extended, and for this movement you may need a wider base, placing your feet further apart than in a normal push-up.','Maintain good posture, and place your free hand behind your back. This will be your starting position.','Lower yourself by allowing the elbow to flex until you touch the ground.','Descend slowly, and reverse direction be extending the arm to return to the starting position.'],'Begin laying prone on the ground. Move yourself into a position supporting your weight on your toes and one arm. Your working arm should be placed directly under the shoulder, fully extended. Your legs should be extended, and for this movement you may need a wider base, placing your feet further apart than in a normal push-up. Maintain good posture, and place your free hand behind your back. This will be your starting position. Lower yourself by allowing the elbow to flex until you touch the ground. Descend slowly, and reverse direction be extending the arm to return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Arm_Push-Up/0.jpg','exercisedb',true),('Single-Cone_Sprint_Drill','Single-Cone Sprint Drill','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'otro','plyometrics',ARRAY['This drill teaches quick foot action. You need a single cone. Begin standing next to the cone with one arm back and one arm forward.','Chop the feet as quickly as possible, blocking with the arms. Circle the cone, keep your knees up, with violent foot action.','Rest after three trips around the cone.'],'This drill teaches quick foot action. You need a single cone. Begin standing next to the cone with one arm back and one arm forward. Chop the feet as quickly as possible, blocking with the arms. Circle the cone, keep your knees up, with violent foot action. Rest after three trips around the cone.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Cone_Sprint_Drill/0.jpg','exercisedb',true),('Single-Leg_High_Box_Squat','Single-Leg High Box Squat','cuádriceps',ARRAY['glúteos','isquiotibiales'],'otro','strength',ARRAY['Position a box in a rack. Secure a band or rope in place above the box.','Standing in front of it, step onto the box to a full standing position, letting your other leg remain unsupported. Hold onto the band for balance','. Continue stepping up and down on the same leg before switching to the opposite side.'],'Position a box in a rack. Secure a band or rope in place above the box. Standing in front of it, step onto the box to a full standing position, letting your other leg remain unsupported. Hold onto the band for balance . Continue stepping up and down on the same leg before switching to the opposite side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_High_Box_Squat/0.jpg','exercisedb',true),('Single-Leg_Hop_Progression','Single-Leg Hop Progression','cuádriceps',ARRAY['abductores','aductores','pantorrillas','isquiotibiales'],'otro','plyometrics',ARRAY['Arrange a line of cones in front of you. Assume a relaxed standing position, balanced on one leg. Raise the knee of your opposite leg. This will be your starting position.','Hop forward, jumping and landing with the same leg over the cone.','Use a countermovement jump to hop from cone to cone.','At the end, turn around and go back on the other leg.'],'Arrange a line of cones in front of you. Assume a relaxed standing position, balanced on one leg. Raise the knee of your opposite leg. This will be your starting position. Hop forward, jumping and landing with the same leg over the cone. Use a countermovement jump to hop from cone to cone. At the end, turn around and go back on the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Hop_Progression/0.jpg','exercisedb',true),('Single-Leg_Lateral_Hop','Single-Leg Lateral Hop','cuádriceps',ARRAY['abductores','aductores','pantorrillas','isquiotibiales'],'otro','plyometrics',ARRAY['Stand to the side of a cone or hurdle. To get into the start position, stand on one leg with your knee slightly bent.','To begin, execute a counterjump to hop sideways over the cone.','Land on your jumping leg, and immediately rebound out of it by jumping back to the start position.','Continue hopping back and forth.'],'Stand to the side of a cone or hurdle. To get into the start position, stand on one leg with your knee slightly bent. To begin, execute a counterjump to hop sideways over the cone. Land on your jumping leg, and immediately rebound out of it by jumping back to the start position. Continue hopping back and forth.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Lateral_Hop/0.jpg','exercisedb',true);